import{_ as t,c as a,o as s,aj as i}from"./chunks/framework.guNMSiFm.js";const k=JSON.parse('{"title":"Events","description":"","frontmatter":{},"headers":[],"relativePath":"blockchain/events.md","filePath":"blockchain/events.md","lastUpdated":1777621302000}'),n={name:"blockchain/events.md"};function r(h,e,o,l,p,d){return s(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to &quot;Events&quot;">​</a></h1><p>Events are emitted when certain things happen within the blockchain, e.g. a new account is created or a block is committed. There are different types of events:</p><ul><li>pipeline events</li><li>data events</li><li>time events</li><li>trigger execution events</li></ul><h2 id="pipeline-events" tabindex="-1">Pipeline Events <a class="header-anchor" href="#pipeline-events" aria-label="Permalink to &quot;Pipeline Events&quot;">​</a></h2><p>Pipeline events are emitted when transactions are submitted, executed, or committed to a block. A pipeline event contains the following information: the kind of entity that caused an event (transaction or block), its hash and status. The status can be either <code>Validating</code> (validation in progress), <code>Rejected</code>, or <code>Committed</code>. If an entity was rejected, the reason for the rejection is provided.</p><h3 id="try-it-on-taira" tabindex="-1">Try It on Taira <a class="header-anchor" href="#try-it-on-taira" aria-label="Permalink to &quot;Try It on Taira&quot;">​</a></h3><p>Check that the public pipeline event stream is mounted:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSI</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://taira.sora.org/v1/events/sse</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sed</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;1,12p&#39;</span></span></code></pre></div><p>For a snapshot you can inspect without keeping a stream open, read recent explorer transactions:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsS</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;https://taira.sora.org/v1/explorer/transactions?page=1&amp;per_page=5&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{pagination, txs: [.items[] | {hash, block, status, executable}]}&#39;</span></span></code></pre></div><p>Open the SSE route in a terminal when you need live events:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsS</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://taira.sora.org/v1/events/sse</span></span></code></pre></div><p>If no transactions are submitted while the stream is open, the command can stay quiet even though the route is healthy.</p><h2 id="data-events" tabindex="-1">Data Events <a class="header-anchor" href="#data-events" aria-label="Permalink to &quot;Data Events&quot;">​</a></h2><p>Data events are emitted when there is a change related to ledger data such as peers, domains, accounts, assets, asset definitions, NFTs, triggers, roles, on-chain configuration, executor state, proofs, confidential assets, bridges, or SORA/Nexus-specific objects. These types of events are used in <a href="./filters.html#data-event-filters">data event filters</a>.</p><h2 id="time-events" tabindex="-1">Time Events <a class="header-anchor" href="#time-events" aria-label="Permalink to &quot;Time Events&quot;">​</a></h2><p>Time events are emitted when the world state view is ready to handle <a href="./triggers.html#time-triggers">time triggers</a>.</p><h2 id="trigger-execution-events" tabindex="-1">Trigger Execution Events <a class="header-anchor" href="#trigger-execution-events" aria-label="Permalink to &quot;Trigger Execution Events&quot;">​</a></h2><p>Trigger execution events are emitted when the <a href="./instructions.html#executetrigger"><code>ExecuteTrigger</code></a> instruction is executed. Trigger completion events are emitted after a trigger action finishes.</p>`,19)])])}const g=t(n,[["render",r]]);export{k as __pageData,g as default};
